"use client";

import type { PostTransformEvent } from "@repo/app-providers/contracts";
import { formatDistanceToNow } from "date-fns";

interface EventDetailProps {
  event: {
    id: number;
    sourceEvent: PostTransformEvent;
    ingestionSource: string;
    receivedAt: string;
    createdAt: string;
  };
}

export function EventDetail({ event }: EventDetailProps) {
  const { sourceEvent, ingestionSource, receivedAt, createdAt } = event;

  return (
    <div className="space-y-4 border-border/40 border-t bg-muted/20 px-6 py-4 text-sm">
      {/* Body */}
      {sourceEvent.body && (
        <div>
          <p className="mb-1 font-medium text-muted-foreground text-xs uppercase tracking-wide">
            Body
          </p>
          <p className="whitespace-pre-wrap break-words text-foreground/80 text-sm leading-relaxed">
            {sourceEvent.body.length > 1000
              ? `${sourceEvent.body.slice(0, 1000)}…`
              : sourceEvent.body}
          </p>
        </div>
      )}

      {/* Entity */}
      <div>
        <p className="mb-1 font-medium text-muted-foreground text-xs uppercase tracking-wide">
          Entity
        </p>
        <dl className="grid grid-cols-2 gap-x-4 gap-y-1">
          <dt className="truncate text-muted-foreground text-xs">Type</dt>
          <dd className="truncate font-mono text-xs">
            {sourceEvent.entity.entityType}
          </dd>
          <dt className="truncate text-muted-foreground text-xs">ID</dt>
          <dd className="truncate font-mono text-xs">
            {sourceEvent.entity.entityId}
          </dd>
          {sourceEvent.entity.state && (
            <>
              <dt className="truncate text-muted-foreground text-xs">State</dt>
              <dd className="truncate font-mono text-xs">
                {sourceEvent.entity.state}
              </dd>
            </>
          )}
        </dl>
      </div>

      {/* Relations */}
      {sourceEvent.relations.length > 0 && (
        <div>
          <p className="mb-1 font-medium text-muted-foreground text-xs uppercase tracking-wide">
            Relations
          </p>
          <div className="flex flex-wrap gap-1.5">
            {sourceEvent.relations.map((rel, i) => (
              <span
                className="inline-flex items-center gap-1 rounded-full border border-border/60 bg-muted px-2 py-0.5 text-xs"
                key={i}
              >
                <span className="text-muted-foreground capitalize">
                  {rel.entityType}
                </span>
                {rel.url ? (
                  <a
                    className="font-mono text-primary hover:underline"
                    href={rel.url}
                    rel="noopener noreferrer"
                    target="_blank"
                  >
                    {rel.entityId}
                  </a>
                ) : (
                  <span className="font-mono">{rel.entityId}</span>
                )}
                <span className="text-muted-foreground/70">
                  {rel.relationshipType}
                </span>
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Attributes */}
      {(() => {
        const entries = Object.entries(sourceEvent.attributes);
        if (entries.length === 0) {
          return null;
        }
        return (
          <div>
            <p className="mb-1 font-medium text-muted-foreground text-xs uppercase tracking-wide">
              Attributes
            </p>
            <dl className="grid grid-cols-2 gap-x-4 gap-y-1">
              {entries.map(([key, value]) => (
                <div className="contents" key={key}>
                  <dt className="truncate text-muted-foreground text-xs">
                    {key}
                  </dt>
                  <dd className="truncate font-mono text-xs">
                    {String(value)}
                  </dd>
                </div>
              ))}
            </dl>
          </div>
        );
      })()}

      {/* Timestamps & IDs */}
      <div className="grid grid-cols-2 gap-x-4 gap-y-1 border-border/40 border-t pt-1">
        <div className="text-muted-foreground text-xs">Event time</div>
        <div className="font-mono text-xs">
          {formatDistanceToNow(new Date(sourceEvent.occurredAt), {
            addSuffix: true,
          })}
        </div>
        <div className="text-muted-foreground text-xs">Received</div>
        <div className="font-mono text-xs">
          {formatDistanceToNow(new Date(receivedAt), { addSuffix: true })}
        </div>
        <div className="text-muted-foreground text-xs">Stored</div>
        <div className="font-mono text-xs">
          {formatDistanceToNow(new Date(createdAt), { addSuffix: true })}
        </div>
        <div className="text-muted-foreground text-xs">Source ID</div>
        <div className="truncate font-mono text-xs">{sourceEvent.sourceId}</div>
        <div className="text-muted-foreground text-xs">Ingestion</div>
        <div className="font-mono text-xs">{ingestionSource}</div>
      </div>
    </div>
  );
}

import type { PostTransformEvent } from "@repo/app-providers/contracts";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  jsonb,
  pgTable,
  timestamp,
  varchar,
} from "drizzle-orm/pg-core";

/**
 * Org Ingest Log stores transformed PostTransformEvent objects
 * produced by the ingress pipeline's per-provider transformers.
 *
 * Only successfully transformed events are stored (unsupported event types
 * are skipped). Raw payloads exist upstream in QStash and gatewayWebhookDeliveries.
 *
 * Primary consumers:
 * - SSE endpoint (/api/gateway/stream) — catch-up on reconnect via Last-Event-ID
 * - Future: dashboard real-time feed, agent VM notifications
 *
 * The BIGINT identity PK serves as a monotonic cursor for SSE Last-Event-ID.
 */
export const orgIngestLogs = pgTable(
  "lightfast_org_ingest_logs",
  {
    /**
     * Monotonic cursor — used as SSE Last-Event-ID for catch-up on reconnect.
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    /**
     * Delivery ID from the platform ingest pipeline — traces back to gatewayWebhookDeliveries for debugging.
     */
    deliveryId: varchar("delivery_id", { length: 191 }).notNull(),

    /**
     * Full transformed event — the canonical event representation.
     * Contains: deliveryId, sourceId, provider, eventType, occurredAt,
     * entity, relations, title, body, attributes.
     */
    sourceEvent: jsonb("source_event").$type<PostTransformEvent>().notNull(),

    /**
     * How this event was ingested: webhook, backfill, manual, or api.
     */
    ingestionSource: varchar("ingestion_source", { length: 20 })
      .default("webhook")
      .notNull(),

    /**
     * When the original webhook was received by the platform ingest service.
     */
    receivedAt: timestamp("received_at", {
      mode: "string",
      withTimezone: true,
    }).notNull(),

    /**
     * When this record was created.
     */
    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => ({
    /**
     * SSE catch-up: WHERE clerk_org_id = ? AND id > ? ORDER BY id LIMIT 1000
     * Composite index enables efficient B-tree range scan.
     */
    orgEventCursorIdx: index("org_event_cursor_idx").on(
      table.clerkOrgId,
      table.id
    ),

    /**
     * Trace back to the platform ingest delivery record for debugging.
     */
    eventDeliveryIdx: index("org_event_delivery_idx").on(table.deliveryId),

    /**
     * Filter events by provider (replaces dropped source/sourceType columns).
     * Expression index on JSONB provider field.
     */
    eventProviderIdx: index("org_ingest_log_provider_idx").on(
      sql`(${table.sourceEvent}->>'provider')`
    ),

    /**
     * Date-range filtering: WHERE clerk_org_id = ? AND received_at >= ?
     */
    orgEventDateIdx: index("org_event_date_idx").on(
      table.clerkOrgId,
      table.receivedAt
    ),
  })
);

// Type exports
export type OrgIngestLog = typeof orgIngestLogs.$inferSelect;
export type InsertOrgIngestLog = typeof orgIngestLogs.$inferInsert;

