4	import type { EntityEventNotification } from "@repo/app-upstash-realtime";
5	import { useRealtime } from "@repo/app-upstash-realtime/client";
6	import { Badge } from "@repo/ui/components/ui/badge";
7	import { Button } from "@repo/ui/components/ui/button";
8	import {
9	  useSuspenseInfiniteQuery,
10	  useSuspenseQuery,
11	} from "@tanstack/react-query";
12	import { formatDistanceToNow } from "date-fns";
13	import { ArrowLeft, ExternalLink } from "lucide-react";
14	import Link from "next/link";
15	import { useParams } from "next/navigation";
16	import { useMemo, useState } from "react";
17	import type { EntityEvent } from "~/types";
18	import { EntityEventRow } from "./entity-event-row";
19	
20	interface EntityDetailViewProps {
21	  entityId: string;
22	}
23	
24	export function EntityDetailView({ entityId }: EntityDetailViewProps) {
25	  const trpc = useTRPC();
26	  const params = useParams<{ slug: string }>();
27	
28	  const { data: entity } = useSuspenseQuery(
29	    trpc.entities.get.queryOptions({ externalId: entityId })
30	  );
31	
32	  const {
33	    data: eventsData,
34	    hasNextPage,
35	    isFetchingNextPage,
36	    fetchNextPage,
37	  } = useSuspenseInfiniteQuery(
38	    trpc.entities.getEvents.infiniteQueryOptions(
39	      { externalId: entityId, limit: 20 },
40	      {
41	        getNextPageParam: (lastPage) => lastPage.nextCursor ?? undefined,
42	      }
43	    )
44	  );
45	
46	  const dbEvents = useMemo(
47	    () => eventsData.pages.flatMap((page) => page.events),
48	    [eventsData.pages]
49	  );
50	
51	  // Live events — prepend new events for this entity in real time
52	  const [liveEvents, setLiveEvents] = useState<EntityEventNotification[]>([]);
53	  const isDefaultView = eventsData.pages.length <= 1;
54	
55	  const { status } = useRealtime({
56	    channels: entity.clerkOrgId ? [`org-${entity.clerkOrgId}`] : [],
57	    events: ["org.entityEvent"],
58	    enabled: !!entity.clerkOrgId && isDefaultView,
59	    onData({ data: notification }) {
60	      if (notification.entityExternalId !== entityId) {
61	        return;
62	      }
63	      if (notification.clerkOrgId !== entity.clerkOrgId) {
64	        return;
65	      }
66	      setLiveEvents((prev) => [notification, ...prev]);
67	    },
68	  });
69	
70	  // Stable set of DB event IDs for dedup
71	  const dbEventIds = useMemo(
72	    () => new Set(dbEvents.map((e) => e.id)),
73	    [dbEvents]
74	  );
75	
76	  // Merge: live prepend + all pages
77	  const allEvents = useMemo(() => {
78	    const newLive = liveEvents.filter((e) => !dbEventIds.has(e.eventId));
79	    const liveAsEvents: EntityEvent[] = newLive.map((e) => ({
80	      id: e.eventId,
81	      externalId: e.eventExternalId,
82	      observationType: e.observationType,
83	      title: e.title,
84	      content: "",
85	      source: e.source,
86	      sourceType: e.sourceType,
87	      sourceId: e.sourceId,
88	      significanceScore: e.significanceScore,
89	      occurredAt: e.occurredAt,
