38	
39	  // Debounced search
40	  const [searchInput, setSearchInput] = useState(filters.search);
41	  const searchDebounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
42	
43	  useEffect(() => {
44	    if (searchDebounceRef.current) {
45	      clearTimeout(searchDebounceRef.current);
46	    }
47	    searchDebounceRef.current = setTimeout(() => {
48	      void setFilters({ search: searchInput });
49	    }, 300);
50	    return () => {
51	      if (searchDebounceRef.current) {
52	        clearTimeout(searchDebounceRef.current);
53	      }
54	    };
55	  }, [searchInput, setFilters]);
56	
57	  const trpc = useTRPC();
58	
59	  const { data, hasNextPage, isFetchingNextPage, fetchNextPage } =
60	    useSuspenseInfiniteQuery(
