137	      createdAt: e.lastSeenAt,
138	    }));
139	    return [...liveAsEntities, ...dbEntities];
140	  }, [liveEntities, dbExternalIds, dbEntities]);
141	
142	  return (
143	    <div className="space-y-4">
144	      {/* Filter bar */}
